                            <div onClick={(e) => e.stopPropagation()} className="flex justify-center">
                              <input
                                type="number"
                                className="w-24 bg-slate-950/80 border border-[rgba(139,92,246,0.3)] rounded py-1 px-2 text-center text-slate-100 font-bold focus:outline-none focus:border-purple-500 focus:ring-1 focus:ring-purple-500"
                                value={tempCompleted[task.id] !== undefined ? tempCompleted[task.id] : (task.completed_quantity ?? 0)}
                                onChange={(e) => handleCompletedChange(task, e.target.value)}
                                step="any"
                                min="0"
                                max={task.total_quantity}
                                disabled={savingId === task.id}
                              />
                            </div>
                          ) : (
                            <span className="text-slate-300">{compDisplay}</span>
                          )}
                        </td>
                        <td className="tabular-nums py-3 px-4 text-slate-300" style={{ textAlign: 'center' }}>
                          {isEditing && hasQty ? (
                            `${(task.total_quantity - (tempCompleted[task.id] !== undefined ? tempCompleted[task.id] : (task.completed_quantity ?? 0))).toLocaleString()} ${unitTrans}`
                          ) : (
                            pendDisplay
                          )}
                        </td>
                        <td className="tabular-nums py-3 px-4" style={{ textAlign: 'center' }}>
                          {isEditing ? (
                            hasQty ? (
                              <span className="tabular-nums font-bold text-purple-400">
                                {(tempProgress[task.id] !== undefined ? tempProgress[task.id] : task.progress_percent).toFixed(2)}%
                              </span>
                            ) : (
                              <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '0.5rem' }} onClick={(e) => e.stopPropagation()}>
                                <input
                                  type="number"
                                  className="w-20 bg-slate-950/80 border border-[rgba(139,92,246,0.3)] rounded py-1 px-2 text-center text-slate-100 font-bold focus:outline-none"
                                  value={progressVal}
                                  onChange={(e) => handleProgressChange(task.id, e.target.value)}
                                  step="0.01"
                                  min="0"
                                  max="100"
                                  disabled={savingId === task.id}
                                />
                                <span className="text-slate-300">%</span>
                              </div>
                            )
                          ) : (
                            <div style={{ display: 'flex', flexDirection: 'column', gap: '4px', alignItems: 'center' }}>
                              <span className="tabular-nums font-bold" style={{ color: task.progress_percent === 100 ? 'var(--success)' : '#e2e8f0' }}>
                                {task.progress_percent.toFixed(2)}%
                              </span>
                              <div className="progress-bar-container" style={{ width: '70px', height: '4px' }}>
                                <div 
                                  className={`progress-bar-fill ${task.progress_percent === 100 ? 'success' : ''}`}
                                  style={{ width: `${task.progress_percent}%` }}
                                ></div>
                              </div>
                            </div>
                          )}
                        </td>
                        <td className="py-3 px-4" style={textDirectionStyle}>
                          {isEditing ? (
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }} onClick={(e) => e.stopPropagation()}>
                              <input
                                type="text"
                                className="w-full bg-slate-950/80 border border-[rgba(139,92,246,0.3)] rounded py-1 px-3 text-slate-100 text-xs focus:outline-none"
                                value={notesVal}
                                onChange={(e) => handleNotesChange(task.id, e.target.value)}
                                placeholder={t('enterNotes')}
                                disabled={savingId === task.id}
                              />
                              <button
                                onClick={() => handleSaveClick(task.id)}
                                className="p-1.5 rounded bg-purple-600 hover:bg-purple-500 text-white transition-colors cursor-pointer"
                                disabled={savingId === task.id}
                              >
                                <Save size={14} />
                              </button>
                            </div>
                          ) : (
                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem', color: 'var(--muted)', fontSize: '0.85rem' }}>
                              <MessageSquare size={14} style={{ color: 'var(--muted)', flexShrink: 0 }} />
                              <span className="text-slate-400 font-medium">{translateText(task.notes, lang) || '-'}</span>
                            </div>
                          )}
                        </td>
                      </tr>
                    );
                  })}
                </React.Fragment>
              );
            })}
          </tbody>
        </table>
      </div>
    </motion.div>
